SELECT ca.*, c.card_name
FROM   CARD_APPLICATIONS ca
INNER JOIN CARDS c ON ca.card_id = c.card_id
WHERE  1 = 1

  AND  ca.application_status = #{applicationStatus}


  AND  ca.apply_channel = #{applyChannel}


  AND  ca.card_id = #{cardId}

ORDER  BY ca.applied_at DESC

SELECT COUNT(1) FROM CARD_APPLICATIONS ca
WHERE 1 = 1

  AND ca.application_status = #{applicationStatus}

mapper.update:
UPDATE CARD_APPLICATIONS
application_status = #{applicationStatus}, updated_at = SYSTIMESTAMP, reviewed_at = SYSTIMESTAMP, approved_limit = #{approvedLimit}, rejection_reason = #{rejectionReason}, reviewed_by = #{reviewedBy},
WHERE application_id = #{applicationId}
